@dataclass(frozen=True)
class NoseGeometryIntent:
    scale_x: float
    scale_y: float
    feather: int
    center_y_ratio: float
    lower_extension_ratio: float
    reason: str
    width_decrease: bool
    length_increase: bool
    length_decrease: bool


@dataclass(frozen=True)
class MouthGeometryIntent:
    scale_x: float
    scale_y: float
    smile_strength: float
    feather: int
    reason: str
    corner_lift: float = 0.0


