def _normalize_text(text: str) -> str:
    normalized = unicodedata.normalize("NFKD", text or "")
    ascii_text = "".join(char for char in normalized if not unicodedata.combining(char))
    return f" {ascii_text.lower().replace('-', ' ')} "


def _has_any_term(normalized_text: str, terms: tuple[str, ...]) -> bool:
    return any(re.search(rf"(?<!\w){re.escape(term)}(?!\w)", normalized_text) for term in terms)


def resolve_nose_geometry_intent(description: str) -> NoseGeometryIntent | None:
    normalized = _normalize_text(description)
    mentions_nose = _has_any_term(normalized, ("nose", "nariz"))
    width_decrease = _has_any_term(normalized, WIDTH_DECREASE_TERMS)
    width_increase = _has_any_term(normalized, WIDTH_INCREASE_TERMS)
    length_decrease = _has_any_term(normalized, LENGTH_DECREASE_TERMS)
    length_increase = _has_any_term(normalized, LENGTH_INCREASE_TERMS)
    if length_decrease:
        length_increase = False

    if not mentions_nose and not (width_decrease or width_increase or length_increase or length_decrease):
        return None
    if not (width_decrease or width_increase or length_increase or length_decrease):
        return None

    scale_x = 1.0
    scale_y = 1.0
    reasons: list[str] = []

    if width_decrease:
        scale_x = 0.78 if length_increase else 0.76
        scale_y = 0.95
        reasons.append("width_decrease")
    elif width_increase:
        scale_x = 1.13
        reasons.append("width_increase")

    if length_increase:
        scale_y = 1.24 if (width_decrease or width_increase) else 1.30
        reasons.append("length_increase")
    elif length_decrease:
        scale_y = 0.74 if (width_decrease or width_increase) else 0.70
        reasons.append("length_decrease")

    length_only = (length_increase or length_decrease) and not (width_decrease or width_increase)
    center_y_ratio = 0.34 if length_decrease else (0.24 if length_increase else 0.58)
    lower_extension_ratio = 0.34 if length_only and length_increase else (0.24 if length_increase else (0.16 if length_decrease else 0.0))
    return NoseGeometryIntent(
        scale_x=scale_x,
        scale_y=scale_y,
        feather=18 if length_only else (20 if length_increase else 18),
        center_y_ratio=center_y_ratio,
        lower_extension_ratio=lower_extension_ratio,
        reason="+".join(reasons),
        width_decrease=width_decrease,
        length_increase=length_increase,
        length_decrease=length_decrease,
    )


def resolve_mouth_geometry_intent(description: str) -> MouthGeometryIntent | None:
    normalized = _normalize_text(description)
    smile = _has_any_term(normalized, SMILE_TERMS)
    mentions_mouth = smile or _has_any_term(normalized, MOUTH_TERMS)
    if not mentions_mouth:
        return None

    width_decrease = _has_any_term(normalized, MOUTH_WIDTH_DECREASE_TERMS)
    width_increase = _has_any_term(normalized, MOUTH_WIDTH_INCREASE_TERMS)
    full_lips = _has_any_term(normalized, FULL_LIPS_TERMS)
    thin_lips = _has_any_term(normalized, THIN_LIPS_TERMS)
    open_mouth = _has_any_term(normalized, OPEN_MOUTH_TERMS)
    closed_mouth = _has_any_term(normalized, CLOSED_MOUTH_TERMS)
    big_smile = _has_any_term(normalized, BIG_SMILE_TERMS)

    scale_x = 1.0
    scale_y = 1.0
    smile_strength = 0.0
    corner_lift = 0.0
    reasons: list[str] = []

    if smile:
        smile_strength = 0.74 if big_smile else 0.52
        reasons.append("smile")
        if big_smile:
            reasons.append("smile_corner_widen")

    if width_decrease:
        scale_x = min(scale_x, 0.82)
        reasons.append("width_decrease")
    elif width_increase:
        if smile:
            smile_strength = max(smile_strength, 0.68)
            scale_x = max(scale_x, 1.20 if big_smile else 1.14)
            reasons.append("smile_corner_widen")
        else:
            scale_x = max(scale_x, 1.18)
            reasons.append("width_increase")
    elif smile and big_smile:
        # "wider/bigger smile": lift the corners and pull them outward.
        corner_lift = 1.25
        smile_strength = max(smile_strength, 0.58)
        if "smile_corner_widen" not in reasons:
            reasons.append("smile_corner_widen")
        reasons.append("smile_corner_lift")

    if closed_mouth:
        scale_y = 0.82
        reasons.append("lip_height_decrease")
    elif thin_lips:
        scale_y = 0.84
        reasons.append("lip_height_decrease")
    elif full_lips or open_mouth:
        if smile and full_lips:
            scale_y = 1.32
            reasons.append("lip_height_increase")
        elif smile and open_mouth:
            scale_y = 1.18
            reasons.append("lip_height_increase")
        elif full_lips:
            scale_y = 1.32
        else:
            scale_y = 1.18
        if not smile or open_mouth:
            reasons.append("lip_height_increase")

    if not reasons:
        return None

    feather = 14
    return MouthGeometryIntent(
        scale_x=scale_x,
        scale_y=scale_y,
        smile_strength=smile_strength,
        feather=feather,
        reason="+".join(dict.fromkeys(reasons)),
        corner_lift=corner_lift,
    )


def compute_mask_bbox(mask_uint8, np):
    ys, xs = np.where(mask_uint8 > 0)
    if len(xs) == 0 or len(ys) == 0:
        return None
    return int(xs.min()), int(ys.min()), int(xs.max()) + 1, int(ys.max()) + 1


def expand_box(box, pad_x: int, pad_y: int, width: int, height: int):
    x1, y1, x2, y2 = box
    return (
        max(0, x1 - pad_x),
        max(0, y1 - pad_y),
        min(width, x2 + pad_x),
        min(height, y2 + pad_y),
    )


def _inner_feather_mask(mask_uint8, feather: int, cv2, np):
    hard = (mask_uint8 > 0).astype(np.uint8)
    if not np.any(hard):
        return hard.astype(np.float32)
    if feather <= 0:
        return hard.astype(np.float32)

    distance = cv2.distanceTransform(hard, cv2.DIST_L2, 5)
    alpha = np.clip(distance / float(max(1, feather)), 0.0, 1.0)
    alpha[hard == 0] = 0.0
    return alpha.astype(np.float32)


def _odd_at_least(value: int, minimum: int = 3) -> int:
    value = max(minimum, int(value))
    return value if value % 2 == 1 else value + 1


def _build_working_mask(target_mask, cv2, np, lower_extension_ratio: float, keepout_mask=None):
    working_mask = (target_mask > 0).astype(np.uint8) * 255
    bbox = compute_mask_bbox(working_mask, np)
    if bbox is None:
        return working_mask

    if lower_extension_ratio > 0:
        height, width = working_mask.shape[:2]
        x1, y1, x2, y2 = bbox
        mask_w = max(1, x2 - x1)
        mask_h = max(1, y2 - y1)
        extension_px = max(2, int(round(mask_h * float(lower_extension_ratio))))
        kernel = cv2.getStructuringElement(
            cv2.MORPH_ELLIPSE,
            (_odd_at_least(mask_w * 0.28), _odd_at_least(extension_px * 2 + 1)),
        )
        expanded = cv2.dilate(working_mask, kernel, iterations=1)
        lower_gate = np.zeros_like(working_mask)
        gate_y1 = max(0, int(round(y1 + mask_h * 0.34)))
        gate_y2 = min(height, y2 + extension_px)
        gate_x1 = max(0, x1 - int(round(mask_w * 0.24)))
        gate_x2 = min(width, x2 + int(round(mask_w * 0.24)))
        lower_gate[gate_y1:gate_y2, gate_x1:gate_x2] = 255
        working_mask = cv2.max(working_mask, cv2.bitwise_and(expanded, lower_gate))

    if keepout_mask is not None and np.any(keepout_mask):
        keepout = cv2.dilate(
            (keepout_mask > 0).astype(np.uint8) * 255,
            cv2.getStructuringElement(cv2.MORPH_ELLIPSE, (7, 7)),
            iterations=1,
        )
        working_mask = cv2.bitwise_and(working_mask, cv2.bitwise_not(keepout))

    return working_mask


def _expand_working_mask_for_geometry(target_mask, working_mask, cv2, np, scale_x: float, scale_y: float, feather: int, keepout_mask=None):
    bbox = compute_mask_bbox(target_mask, np)
    if bbox is None:
        return working_mask

    height, width = target_mask.shape[:2]
    x1, y1, x2, y2 = bbox
    mask_w = max(1, x2 - x1)
    mask_h = max(1, y2 - y1)

    pad_x = int(round(mask_w * (0.05 + abs(float(scale_x) - 1.0) * 0.75)))
    pad_top = int(round(mask_h * (0.02 + max(0.0, float(scale_y) - 1.0) * 0.35)))
    pad_bottom = int(round(mask_h * (0.05 + abs(float(scale_y) - 1.0) * 0.85)))
    pad_x = max(2, min(pad_x, int(round(mask_w * 0.20))))
    pad_top = max(1, min(pad_top, int(round(mask_h * 0.16))))
    pad_bottom = max(2, min(pad_bottom, int(round(mask_h * 0.22))))

    kernel = cv2.getStructuringElement(
        cv2.MORPH_ELLIPSE,
        (_odd_at_least(pad_x * 2 + 1), _odd_at_least(max(pad_top, pad_bottom) * 2 + 1)),
    )
    expanded = cv2.dilate((target_mask > 0).astype(np.uint8) * 255, kernel, iterations=1)

    gate = np.zeros_like(target_mask, dtype=np.uint8)
    gate_y1 = max(0, y1 - pad_top)
    gate_y2 = min(height, y2 + pad_bottom + max(1, feather // 8))
    gate_x1 = max(0, x1 - pad_x)
    gate_x2 = min(width, x2 + pad_x)
    gate[gate_y1:gate_y2, gate_x1:gate_x2] = 255

    expanded = cv2.bitwise_and(expanded, gate)
    working_mask = cv2.max(working_mask, expanded)

    if keepout_mask is not None and np.any(keepout_mask):
        keepout = cv2.dilate(
            (keepout_mask > 0).astype(np.uint8) * 255,
            cv2.getStructuringElement(cv2.MORPH_ELLIPSE, (9, 9)),
            iterations=1,
        )
        working_mask = cv2.bitwise_and(working_mask, cv2.bitwise_not(keepout))

    return working_mask


def _build_lower_nose_cleanup_alpha(target_mask, working_mask, cv2, np, feather: int):
    bbox = compute_mask_bbox(target_mask, np)
    if bbox is None:
        return np.zeros_like(target_mask, dtype=np.float32)

    height, width = target_mask.shape[:2]
    x1, y1, x2, y2 = bbox
    mask_w = max(1, x2 - x1)
    mask_h = max(1, y2 - y1)

    gate = np.zeros_like(target_mask, dtype=np.uint8)
    gate_y1 = max(0, int(round(y1 + mask_h * 0.48)))
    gate_y2 = min(height, y2 + int(round(mask_h * 0.20)))
    gate_x1 = max(0, x1 - int(round(mask_w * 0.20)))
    gate_x2 = min(width, x2 + int(round(mask_w * 0.20)))
    gate[gate_y1:gate_y2, gate_x1:gate_x2] = 255

    kernel = cv2.getStructuringElement(
        cv2.MORPH_ELLIPSE,
        (_odd_at_least(mask_w * 0.26), _odd_at_least(mask_h * 0.16)),
    )
    cleanup = cv2.dilate((target_mask > 0).astype(np.uint8) * 255, kernel, iterations=1)
    cleanup = cv2.bitwise_and(cleanup, gate)
    cleanup = cv2.bitwise_and(cleanup, (working_mask > 0).astype(np.uint8) * 255)
    if not np.any(cleanup):
        return np.zeros_like(target_mask, dtype=np.float32)

    core_kernel = cv2.getStructuringElement(
        cv2.MORPH_ELLIPSE,
        (_odd_at_least(mask_w * 0.10), _odd_at_least(mask_h * 0.08)),
    )
    core = cv2.erode(cleanup, core_kernel, iterations=1)
    blur_size = _odd_at_least(max(3, feather // 2))
    soft_cleanup = cv2.GaussianBlur(cleanup, (blur_size, blur_size), 0)
    alpha = np.clip(soft_cleanup.astype(np.float32) / 255.0, 0.0, 1.0) * 0.98
    alpha[core > 0] = 1.0
    return alpha


def _build_composite_mask(mask_uint8, cv2, np, feather: int):
    hard = (mask_uint8 > 0).astype(np.uint8) * 255
    if feather <= 0 or not np.any(hard):
        return hard

    blur_size = _odd_at_least(max(3, int(round(feather * 0.45))))
    soft = cv2.GaussianBlur(hard, (blur_size, blur_size), 0)
    core_size = _odd_at_least(max(3, int(round(feather * 0.35))))
    core = cv2.erode(
        hard,
        cv2.getStructuringElement(cv2.MORPH_ELLIPSE, (core_size, core_size)),
        iterations=1,
    )
    soft[core > 0] = 255
    return soft.astype(np.uint8)

def _build_mouth_edit_region_mask(
    target_mask,
    anchor_points,
    cv2,
    np,
    feather: int,
    corner_lift: float = 0.0,
    scale_x: float = 1.0,
    scale_y: float = 1.0,
):
    hard = (target_mask > 0).astype(np.uint8) * 255
    bbox = compute_mask_bbox(hard, np)
    if bbox is None:
        return hard

    x1, y1, x2, y2 = bbox
    mouth_w = max(1, x2 - x1)
    mouth_h = max(1, y2 - y1)
    pad_x = max(4, int(round(mouth_w * (0.12 + min(0.10, abs(float(scale_x) - 1.0) * 0.24)))))
    pad_y = max(3, int(round(mouth_h * (0.20 + min(0.10, abs(float(scale_y) - 1.0) * 0.18)))))
    if corner_lift > 0.0:
        pad_x = max(pad_x, int(round(mouth_w * (0.13 + min(0.06, float(corner_lift) * 0.025)))))
        pad_y = max(pad_y, int(round(mouth_h * 0.18)))

    kernel = cv2.getStructuringElement(
        cv2.MORPH_ELLIPSE,
        (_odd_at_least(pad_x * 2 + 1), _odd_at_least(pad_y * 2 + 1)),
    )
    region = cv2.dilate(hard, kernel, iterations=1)

    if anchor_points:
        left_corner = _point_from_anchors(anchor_points, "left_corner", (x1, y1 + mouth_h * 0.55))
        right_corner = _point_from_anchors(anchor_points, "right_corner", (x2 - 1, y1 + mouth_h * 0.55))
        upper_lip = _point_from_anchors(anchor_points, "upper_lip", ((x1 + x2) * 0.5, y1 + mouth_h * 0.38))
        lower_lip = _point_from_anchors(anchor_points, "lower_lip", ((x1 + x2) * 0.5, y1 + mouth_h * 0.66))
        left_x = float(left_corner[0])
        right_x = float(right_corner[0])
        center_x = (left_x + right_x) * 0.5
        center_y = (float(upper_lip[1]) + float(lower_lip[1])) * 0.5
        anchor_w = max(1.0, abs(right_x - left_x), mouth_w * 0.72)
        anchor_h = max(1.0, abs(float(lower_lip[1]) - float(upper_lip[1])), mouth_h * 0.20)
        extra_x = min(0.12, max(0.0, float(corner_lift)) * 0.04)

        support = np.zeros_like(hard)
        cv2.ellipse(
            support,
            (int(round(center_x)), int(round(center_y))),
            (
                max(10, int(round(anchor_w * (0.62 + extra_x)))),
                max(7, int(round(max(anchor_h * 2.6, mouth_h * 0.52)))),
            ),
            0,
            0,
            360,
            255,
            -1,
            cv2.LINE_AA,
        )
        region = cv2.max(region, support)

        gate = np.zeros_like(hard)
        gate_x1 = max(0, int(round(min(left_x, right_x) - anchor_w * (0.38 + extra_x))))
        gate_x2 = min(hard.shape[1], int(round(max(left_x, right_x) + anchor_w * (0.38 + extra_x))))
        gate_y1 = max(0, int(round(float(upper_lip[1]) - max(anchor_h * 2.8, mouth_h * 0.55))))
        gate_y2 = min(hard.shape[0], int(round(float(lower_lip[1]) + max(anchor_h * 3.0, mouth_h * 0.62))))
        if gate_x2 > gate_x1 and gate_y2 > gate_y1:
            gate[gate_y1:gate_y2, gate_x1:gate_x2] = 255
            region = cv2.bitwise_and(region, gate)

    return _build_composite_mask(region, cv2, np, max(6, feather))

def _clean_original_region(base_bgr, cleanup_mask, cv2, radius: int):
    hard = (cleanup_mask > 0).astype("uint8") * 255
    if radius <= 0 or not hard.any():
        return base_bgr.copy()
    return cv2.inpaint(base_bgr, hard, int(max(1, radius)), cv2.INPAINT_TELEA)


def _point_from_anchors(anchor_points: dict[str, tuple[int, int]] | None, name: str, fallback: tuple[float, float]):
    if anchor_points and name in anchor_points:
        return anchor_points[name]
    return fallback


def _smoothstep(value, np):
    value = np.clip(value, 0.0, 1.0)
    return (value * value * (3.0 - 2.0 * value)).astype(np.float32)


def _build_mouth_corner_guard_alpha(target_mask, anchor_points, cv2, np, scale: float = 1.0):
    bbox = compute_mask_bbox(target_mask, np)
    if bbox is None:
        return np.zeros(target_mask.shape[:2], dtype=np.float32)

    x1, y1, x2, y2 = bbox
    mouth_w = max(1, x2 - x1)
    mouth_h = max(1, y2 - y1)
    left_corner = _point_from_anchors(anchor_points, "left_corner", (x1, y1 + mouth_h * 0.55))
    right_corner = _point_from_anchors(anchor_points, "right_corner", (x2 - 1, y1 + mouth_h * 0.55))
    upper_lip = _point_from_anchors(anchor_points, "upper_lip", ((x1 + x2) * 0.5, y1 + mouth_h * 0.38))
    lower_lip = _point_from_anchors(anchor_points, "lower_lip", ((x1 + x2) * 0.5, y1 + mouth_h * 0.66))

    anchor_w = max(1.0, abs(float(right_corner[0]) - float(left_corner[0])))
    anchor_h = max(1.0, abs(float(lower_lip[1]) - float(upper_lip[1])), mouth_h * 0.24)
    axes = (
        max(6, int(round(anchor_w * 0.13 * float(scale)))),
        max(6, int(round(max(anchor_h * 1.15, mouth_h * 0.26) * float(scale)))),
    )

    guard = np.zeros(target_mask.shape[:2], dtype=np.uint8)
    for corner in (left_corner, right_corner):
        cv2.ellipse(
            guard,
            (int(round(corner[0])), int(round(corner[1]))),
            axes,
            0,
            0,
            360,
            255,
            -1,
            cv2.LINE_AA,
        )
    blur_size = _odd_at_least(max(5, int(round(mouth_w * 0.038))))
    guard = cv2.GaussianBlur(guard, (blur_size, blur_size), 0)
    return np.clip(guard.astype(np.float32) / 255.0, 0.0, 1.0)


def _attenuate_mask_by_alpha(mask_uint8, alpha, np, strength: float = 1.0):
    if not np.any(mask_uint8) or not np.any(alpha):
        return mask_uint8
    keep = np.clip(1.0 - alpha.astype(np.float32) * float(strength), 0.0, 1.0)
    return np.clip(mask_uint8.astype(np.float32) * keep, 0, 255).astype(np.uint8)


def _preserve_mouth_corners(base_bgr, edited_bgr, change_mask, target_mask, anchor_points, cv2, np, restore_strength: float = 0.70):
    if not anchor_points:
        return edited_bgr, change_mask
    corner_alpha = _build_mouth_corner_guard_alpha(target_mask, anchor_points, cv2, np, scale=1.05)
    if not np.any(corner_alpha):
        return edited_bgr, change_mask

    restore_strength = float(np.clip(restore_strength, 0.0, 0.90))
    restore_alpha = np.clip(corner_alpha * restore_strength, 0.0, restore_strength)[..., None]
    restored = (
        base_bgr.astype(np.float32) * restore_alpha
        + edited_bgr.astype(np.float32) * (1.0 - restore_alpha)
    ).clip(0, 255).astype(np.uint8)
    protected_mask = _attenuate_mask_by_alpha(change_mask, corner_alpha, np, strength=min(0.75, restore_strength + 0.05))
    return restored, protected_mask


def _build_mouth_lip_band(target_mask, anchor_points, cv2, np, scale_x: float = 1.0, scale_y: float = 1.0):
    bbox = compute_mask_bbox(target_mask, np)
    if bbox is None:
        return np.zeros(target_mask.shape[:2], dtype=np.uint8)

    x1, y1, x2, y2 = bbox
    mouth_w = max(1, x2 - x1)
    mouth_h = max(1, y2 - y1)
    left_corner = _point_from_anchors(anchor_points, "left_corner", (x1, y1 + mouth_h * 0.55))
    right_corner = _point_from_anchors(anchor_points, "right_corner", (x2 - 1, y1 + mouth_h * 0.55))
    upper_lip = _point_from_anchors(anchor_points, "upper_lip", ((x1 + x2) * 0.5, y1 + mouth_h * 0.38))
    lower_lip = _point_from_anchors(anchor_points, "lower_lip", ((x1 + x2) * 0.5, y1 + mouth_h * 0.66))
    upper_outer = _point_from_anchors(anchor_points, "upper_outer", ((x1 + x2) * 0.5, y1 + mouth_h * 0.26))
    lower_outer = _point_from_anchors(anchor_points, "lower_outer", ((x1 + x2) * 0.5, y1 + mouth_h * 0.78))

    center_x = (float(left_corner[0]) + float(right_corner[0])) * 0.5
    anchor_w = max(1.0, abs(float(right_corner[0]) - float(left_corner[0])), mouth_w * 0.72)
    upper_outer_y = float(upper_outer[1])
    lower_outer_y = float(lower_outer[1])
    upper_inner_y = float(upper_lip[1])
    lower_inner_y = float(lower_lip[1])
    upper_depth = max(2.0, abs(upper_inner_y - upper_outer_y), mouth_h * 0.075)
    lower_depth = max(2.0, abs(lower_outer_y - lower_inner_y), mouth_h * 0.075)

    band = np.zeros(target_mask.shape[:2], dtype=np.uint8)
    lip_specs = (
        (upper_outer_y * 0.54 + upper_inner_y * 0.46, upper_depth, 0.58),
        (lower_inner_y * 0.44 + lower_outer_y * 0.56, lower_depth, 0.56),
    )
    for center_y, lip_depth, width_ratio in lip_specs:
        cv2.ellipse(
            band,
            (int(round(center_x)), int(round(center_y))),
            (
                max(8, int(round(anchor_w * width_ratio * float(scale_x)))),
                max(4, int(round(lip_depth * 1.38 * float(scale_y)))),
            ),
            0,
            0,
            360,
            255,
            -1,
            cv2.LINE_AA,
        )
    return band


def _build_upper_lip_support(target_mask, anchor_points, cv2, np, scale_x: float = 1.0, scale_y: float = 1.0, smile_strength: float = 0.0):
    bbox = compute_mask_bbox(target_mask, np)
    if bbox is None:
        return np.zeros(target_mask.shape[:2], dtype=np.uint8)

    x1, y1, x2, y2 = bbox
    mouth_w = max(1, x2 - x1)
    mouth_h = max(1, y2 - y1)
    left_corner = _point_from_anchors(anchor_points, "left_corner", (x1, y1 + mouth_h * 0.55))
    right_corner = _point_from_anchors(anchor_points, "right_corner", (x2 - 1, y1 + mouth_h * 0.55))
    upper_lip = _point_from_anchors(anchor_points, "upper_lip", ((x1 + x2) * 0.5, y1 + mouth_h * 0.38))
    lower_lip = _point_from_anchors(anchor_points, "lower_lip", ((x1 + x2) * 0.5, y1 + mouth_h * 0.66))
    upper_outer = _point_from_anchors(anchor_points, "upper_outer", ((x1 + x2) * 0.5, y1 + mouth_h * 0.26))

    left_x = float(left_corner[0])
    right_x = float(right_corner[0])
    center_x = (left_x + right_x) * 0.5
    upper_inner_y = float(upper_lip[1])
    lower_inner_y = float(lower_lip[1])
    upper_outer_y = min(float(upper_outer[1]), upper_inner_y - 1.0)
    anchor_w = max(1.0, abs(right_x - left_x), mouth_w * 0.72)
    upper_depth = max(2.0, abs(upper_inner_y - upper_outer_y), mouth_h * 0.085)
    upper_center_y = upper_outer_y * 0.62 + upper_inner_y * 0.38

    support = np.zeros(target_mask.shape[:2], dtype=np.uint8)
    cv2.ellipse(
        support,
        (int(round(center_x)), int(round(upper_center_y))),
        (
            max(8, int(round(anchor_w * 0.55 * float(scale_x)))),
            max(4, int(round(upper_depth * (1.30 + abs(float(scale_y) - 1.0) * 0.55)))),
        ),
        0,
        0,
        360,
        255,
        -1,
        cv2.LINE_AA,
    )

    if smile_strength > 0:
        corner_axes = (
            max(4, int(round(anchor_w * (0.050 + min(0.018, float(smile_strength) * 0.010))))),
            max(3, int(round(max(upper_depth * 0.95, mouth_h * 0.085)))),
        )
        for corner in (left_corner, right_corner):
            cv2.ellipse(
                support,
                (int(round(corner[0])), int(round(float(corner[1]) - upper_depth * 0.10))),
                corner_axes,
                0,
                0,
                360,
                255,
                -1,
                cv2.LINE_AA,
            )

    gate = np.zeros_like(support)
    gate_x1 = max(0, int(round(min(left_x, right_x) - anchor_w * 0.08)))
    gate_x2 = min(target_mask.shape[1], int(round(max(left_x, right_x) + anchor_w * 0.08)))
    gate_y1 = max(0, int(round(upper_outer_y - upper_depth * (0.70 + max(0.0, float(scale_y) - 1.0) * 0.18))))
    gate_y2 = min(target_mask.shape[0], int(round(min(lower_inner_y, upper_inner_y + upper_depth * 0.34))))
    if gate_x2 > gate_x1 and gate_y2 > gate_y1:
        gate[gate_y1:gate_y2, gate_x1:gate_x2] = 255
        support = cv2.bitwise_and(support, gate)

    shell = cv2.dilate(
        (target_mask > 0).astype(np.uint8) * 255,
        cv2.getStructuringElement(cv2.MORPH_ELLIPSE, (5, 5)),
        iterations=1,
    )
    support = cv2.bitwise_and(support, shell)

    inner_alpha = _build_mouth_inner_guard_alpha(target_mask, anchor_points, cv2, np, scale=0.88)
    if np.any(inner_alpha):
        support = cv2.bitwise_and(support, cv2.bitwise_not((inner_alpha > 0.34).astype(np.uint8) * 255))

    skin_alpha = _build_upper_lip_skin_guard_alpha(target_mask, anchor_points, cv2, np, scale=1.04)
    if anchor_points and "upper_outer" in anchor_points:
        skin_alpha = skin_alpha.copy()
        skin_alpha[int(max(0, round(float(anchor_points["upper_outer"][1]) - upper_depth * 0.08))):, :] = 0.0
    if np.any(skin_alpha):
        support = cv2.bitwise_and(support, cv2.bitwise_not((skin_alpha > 0.35).astype(np.uint8) * 255))

    support = cv2.dilate(
        support,
        cv2.getStructuringElement(cv2.MORPH_ELLIPSE, (3, 3)),
        iterations=1,
    )
    return support
def _build_lower_lip_support(target_mask, anchor_points, cv2, np, scale_x: float = 1.0, scale_y: float = 1.0, smile_strength: float = 0.0):
    bbox = compute_mask_bbox(target_mask, np)
    if bbox is None:
        return np.zeros(target_mask.shape[:2], dtype=np.uint8)

    x1, y1, x2, y2 = bbox
    mouth_w = max(1, x2 - x1)
    mouth_h = max(1, y2 - y1)
    left_corner = _point_from_anchors(anchor_points, "left_corner", (x1, y1 + mouth_h * 0.55))
    right_corner = _point_from_anchors(anchor_points, "right_corner", (x2 - 1, y1 + mouth_h * 0.55))
    upper_lip = _point_from_anchors(anchor_points, "upper_lip", ((x1 + x2) * 0.5, y1 + mouth_h * 0.38))
    lower_lip = _point_from_anchors(anchor_points, "lower_lip", ((x1 + x2) * 0.5, y1 + mouth_h * 0.66))
    lower_outer = _point_from_anchors(anchor_points, "lower_outer", ((x1 + x2) * 0.5, y1 + mouth_h * 0.78))

    left_x = float(left_corner[0])
    right_x = float(right_corner[0])
    center_x = (left_x + right_x) * 0.5
    lower_inner_y = float(lower_lip[1])
    lower_outer_y = max(float(lower_outer[1]), lower_inner_y + 1.0)
    upper_inner_y = float(upper_lip[1])
    anchor_w = max(1.0, abs(right_x - left_x), mouth_w * 0.72)
    lower_depth = max(2.0, abs(lower_outer_y - lower_inner_y), mouth_h * 0.085)
    lower_center_y = lower_inner_y * 0.34 + lower_outer_y * 0.66

    support = np.zeros(target_mask.shape[:2], dtype=np.uint8)
    cv2.ellipse(
        support,
        (int(round(center_x)), int(round(lower_center_y))),
        (
            max(8, int(round(anchor_w * 0.56 * float(scale_x)))),
            max(4, int(round(lower_depth * (1.22 + max(0.0, float(scale_y) - 1.0) * 0.35)))),
        ),
        0,
        0,
        360,
        255,
        -1,
        cv2.LINE_AA,
    )

    if smile_strength > 0:
        corner_axes = (
            max(5, int(round(anchor_w * (0.070 + min(0.020, float(smile_strength) * 0.012))))),
            max(4, int(round(max(lower_depth * 1.05, mouth_h * 0.105)))),
        )
        for corner in (left_corner, right_corner):
            cv2.ellipse(
                support,
                (int(round(corner[0])), int(round(float(corner[1]) + lower_depth * 0.18))),
                corner_axes,
                0,
                0,
                360,
                255,
                -1,
                cv2.LINE_AA,
            )

    gate = np.zeros_like(support)
    gate_x1 = max(0, int(round(min(left_x, right_x) - anchor_w * 0.10)))
    gate_x2 = min(target_mask.shape[1], int(round(max(left_x, right_x) + anchor_w * 0.10)))
    gate_y1 = max(0, int(round(max(upper_inner_y, lower_inner_y - lower_depth * 0.28))))
    gate_y2 = min(target_mask.shape[0], int(round(lower_outer_y + lower_depth * (0.80 + max(0.0, float(scale_y) - 1.0) * 0.16))))
    if gate_x2 > gate_x1 and gate_y2 > gate_y1:
        gate[gate_y1:gate_y2, gate_x1:gate_x2] = 255
        support = cv2.bitwise_and(support, gate)

    shell = cv2.dilate(
        (target_mask > 0).astype(np.uint8) * 255,
        cv2.getStructuringElement(cv2.MORPH_ELLIPSE, (5, 5)),
        iterations=1,
    )
    support = cv2.bitwise_and(support, shell)

    inner_alpha = _build_mouth_inner_guard_alpha(target_mask, anchor_points, cv2, np, scale=0.92)
    if np.any(inner_alpha):
        support = cv2.bitwise_and(support, cv2.bitwise_not((inner_alpha > 0.30).astype(np.uint8) * 255))
    upper_alpha = _build_upper_lip_guard_alpha(target_mask, anchor_points, cv2, np, scale=1.18)
    if np.any(upper_alpha):
        support = cv2.bitwise_and(support, cv2.bitwise_not((upper_alpha > 0.04).astype(np.uint8) * 255))
    lower_skin_alpha = _build_lower_mouth_skin_guard_alpha(
        target_mask,
        anchor_points,
        cv2,
        np,
        scale=1.0 + max(0.0, float(scale_y) - 1.0) * 0.12,
    )
    if np.any(lower_skin_alpha):
        support = cv2.bitwise_and(support, cv2.bitwise_not((lower_skin_alpha > 0.28).astype(np.uint8) * 255))

    support = cv2.dilate(
        support,
        cv2.getStructuringElement(cv2.MORPH_ELLIPSE, (3, 3)),
        iterations=1,
    )
    return support

def _build_mouth_composition_support(
    target_mask,
    anchor_points,
    cv2,
    np,
    smile_strength: float = 0.0,
    scale_y: float = 1.0,
):
    bbox = compute_mask_bbox(target_mask, np)
    if bbox is None:
        return np.zeros(target_mask.shape[:2], dtype=np.uint8)

    x1, y1, x2, y2 = bbox
    mouth_w = max(1, x2 - x1)
    mouth_h = max(1, y2 - y1)
    left_corner = _point_from_anchors(anchor_points, "left_corner", (x1, y1 + mouth_h * 0.55))
    right_corner = _point_from_anchors(anchor_points, "right_corner", (x2 - 1, y1 + mouth_h * 0.55))
    upper_lip = _point_from_anchors(anchor_points, "upper_lip", ((x1 + x2) * 0.5, y1 + mouth_h * 0.38))
    lower_lip = _point_from_anchors(anchor_points, "lower_lip", ((x1 + x2) * 0.5, y1 + mouth_h * 0.66))

    anchor_w = max(1.0, abs(float(right_corner[0]) - float(left_corner[0])), mouth_w * 0.72)
    anchor_h = max(1.0, abs(float(lower_lip[1]) - float(upper_lip[1])), mouth_h * 0.20)
    lower_support = _build_lower_lip_support(
        target_mask,
        anchor_points,
        cv2,
        np,
        scale_x=1.04 + min(0.04, max(0.0, float(smile_strength)) * 0.020),
        scale_y=1.07 + min(0.14, max(0.0, float(scale_y) - 1.0) * 0.32),
        smile_strength=smile_strength,
    )
    upper_support = _build_upper_lip_support(
        target_mask,
        anchor_points,
        cv2,
        np,
        scale_x=1.03 + min(0.04, max(0.0, float(smile_strength)) * 0.018),
        scale_y=1.12 + min(0.20, abs(float(scale_y) - 1.0) * 0.50),
        smile_strength=smile_strength,
    )
    support = cv2.max(lower_support, upper_support)


    gate = np.zeros_like(support)
    pad_x = int(round(anchor_w * 0.35))
    pad_top = int(round(max(anchor_h * 2.80, mouth_h * 0.52)))
    pad_bottom = int(round(max(anchor_h * 3.20, mouth_h * 0.62)))
    gate_x1 = max(0, int(round(min(float(left_corner[0]), float(right_corner[0])) - pad_x)))
    gate_x2 = min(target_mask.shape[1], int(round(max(float(left_corner[0]), float(right_corner[0])) + pad_x)))
    gate_y1 = max(0, int(round(float(upper_lip[1]) - pad_top)))
    gate_y2 = min(target_mask.shape[0], int(round(float(lower_lip[1]) + pad_bottom)))
    if gate_x2 > gate_x1 and gate_y2 > gate_y1:
        gate[gate_y1:gate_y2, gate_x1:gate_x2] = 255
        support = cv2.bitwise_and(support, gate)

    support = cv2.dilate(
        support,
        cv2.getStructuringElement(cv2.MORPH_ELLIPSE, (3, 3)),
        iterations=1,
    )
    return support


def _apply_visible_lip_fullness(base_bgr, edited_bgr, target_mask, anchor_points, cv2, np, keepout_mask=None, strength: float = 0.90):
    bbox = compute_mask_bbox(target_mask, np)
    if bbox is None or strength <= 0:
        return edited_bgr, np.zeros(target_mask.shape[:2], dtype=np.uint8)

    x1, y1, x2, y2 = bbox
    mouth_w = max(1, x2 - x1)
    mouth_h = max(1, y2 - y1)
    hard = (target_mask > 0).astype(np.uint8) * 255

    sample_band = _build_mouth_lip_band(target_mask, anchor_points, cv2, np, scale_x=1.02, scale_y=1.02)
    band = _build_mouth_lip_band(target_mask, anchor_points, cv2, np, scale_x=1.04, scale_y=1.07)
    lip_core = cv2.bitwise_and(hard, sample_band)
    if not np.any(lip_core):
        return edited_bgr, np.zeros(target_mask.shape[:2], dtype=np.uint8)
    expand_kernel = cv2.getStructuringElement(
        cv2.MORPH_ELLIPSE,
        (
            _odd_at_least(max(3, int(round(mouth_w * 0.028)))),
            _odd_at_least(max(3, int(round(mouth_h * 0.10)))),
        ),
    )
    expanded = cv2.dilate(lip_core, expand_kernel, iterations=1)
    expanded = cv2.bitwise_and(expanded, band)
    expanded = cv2.bitwise_and(expanded, hard)
    if keepout_mask is not None and np.any(keepout_mask):
        keepout = cv2.dilate(
            (keepout_mask > 0).astype(np.uint8) * 255,
            cv2.getStructuringElement(cv2.MORPH_ELLIPSE, (7, 3)),
            iterations=1,
        )
        expanded = cv2.bitwise_and(expanded, cv2.bitwise_not(keepout))

    inner_alpha = _build_mouth_inner_guard_alpha(expanded, anchor_points, cv2, np, keepout_mask=keepout_mask, scale=0.82)
    sample_mask = lip_core
    if np.any(inner_alpha):
        sample_mask = cv2.bitwise_and(sample_mask, cv2.bitwise_not((inner_alpha > 0.42).astype(np.uint8) * 255))

    hsv = cv2.cvtColor(base_bgr, cv2.COLOR_BGR2HSV)
    sample_pixels = sample_mask > 0
    if int(sample_pixels.sum()) < 24:
        return edited_bgr, np.zeros(target_mask.shape[:2], dtype=np.uint8)

    sample_hsv_all = hsv[sample_pixels].astype(np.float32)
    hue = sample_hsv_all[:, 0]
    sat = sample_hsv_all[:, 1]
    val = sample_hsv_all[:, 2]
    red_pink = (((hue <= 18) | (hue >= 145)) & (sat > 20) & (val > 35))
    saturated = (sat > 35) & (val > 40)
    color_candidates = red_pink if int(red_pink.sum()) >= max(12, int(sample_hsv_all.shape[0] * 0.06)) else saturated
    force_lip_hue = int(color_candidates.sum()) >= max(12, int(sample_hsv_all.shape[0] * 0.04))

    if force_lip_hue:
        sample_hsv = sample_hsv_all[color_candidates]
        sample_h = sample_hsv[:, 0].copy()
        if np.any(sample_h < 20) and np.any(sample_h > 145):
            sample_h = np.where(sample_h > 90, sample_h - 180, sample_h)
        target_h = float(np.median(sample_h))
        if target_h < 0:
            target_h += 180.0
        target_s = float(np.clip(np.percentile(sample_hsv[:, 1], 72) * 1.12, 32.0, 160.0))
        target_v = float(np.clip(np.percentile(sample_hsv[:, 2], 62) * 1.02, 38.0, 245.0))
        color_confidence = float(np.clip((np.percentile(sample_hsv[:, 1], 70) - 20.0) / 80.0, 0.40, 1.0))
    else:
        target_h = None
        target_s = float(np.clip(np.percentile(sample_hsv_all[:, 1], 70) * 1.80 + 22.0, 55.0, 180.0))
        target_v = float(np.clip(np.percentile(sample_hsv_all[:, 2], 55) * 0.90, 32.0, 220.0))
        color_confidence = 0.55

    color_hsv = hsv.astype(np.float32)
    if force_lip_hue:
        color_hsv[..., 0] = target_h
        color_hsv[..., 1] = np.maximum(color_hsv[..., 1], target_s)
        color_hsv[..., 2] = np.clip(color_hsv[..., 2] * 0.86 + target_v * 0.14, 0, 255)
    else:
        color_hsv[..., 1] = np.maximum(np.clip(color_hsv[..., 1] * 1.35 + 12.0, 0, 255), target_s)
        color_hsv[..., 2] = np.clip(color_hsv[..., 2] * 0.86 + target_v * 0.14, 0, 255)
    color_layer = cv2.cvtColor(color_hsv.astype(np.uint8), cv2.COLOR_HSV2BGR)
    blurred_base = cv2.GaussianBlur(base_bgr, (0, 0), 1.1).astype(np.float32)
    detail = np.clip(base_bgr.astype(np.float32) - blurred_base, -22.0, 22.0)
    color_layer = (color_layer.astype(np.float32) + detail * 0.55).clip(0, 255).astype(np.uint8)

    soft = cv2.GaussianBlur(
        expanded,
        (_odd_at_least(max(5, int(round(mouth_w * 0.08)))), _odd_at_least(max(5, int(round(mouth_h * 0.10))))),
        0,
    ).astype(np.float32) / 255.0
    original_core = cv2.erode(
        lip_core,
        cv2.getStructuringElement(cv2.MORPH_ELLIPSE, (5, 3)),
        iterations=1,
    )
    expansion_only = cv2.bitwise_and(expanded, cv2.bitwise_not(original_core))
    expansion_soft = cv2.GaussianBlur(
        expansion_only,
        (_odd_at_least(max(5, int(round(mouth_w * 0.06)))), _odd_at_least(max(5, int(round(mouth_h * 0.08))))),
        0,
    ).astype(np.float32) / 255.0

    alpha = np.maximum(soft * (0.30 + 0.12 * color_confidence), expansion_soft * float(strength) * (0.44 + 0.20 * color_confidence))
    if np.any(inner_alpha):
        alpha *= 1.0 - np.clip(inner_alpha * 0.88, 0.0, 0.88)
    alpha = np.clip(alpha, 0.0, 0.50)[..., None]
    output = (
        edited_bgr.astype(np.float32) * (1.0 - alpha)
        + color_layer.astype(np.float32) * alpha
    ).clip(0, 255).astype(np.uint8)
    change_mask = (np.clip(alpha[..., 0] * 255.0, 0, 255)).astype(np.uint8)
    return output, change_mask


def _build_mouth_inner_guard_alpha(target_mask, anchor_points, cv2, np, keepout_mask=None, scale: float = 1.0):
    bbox = compute_mask_bbox(target_mask, np)
    if bbox is None:
        return np.zeros(target_mask.shape[:2], dtype=np.float32)

    x1, y1, x2, y2 = bbox
    mouth_w = max(1, x2 - x1)
    mouth_h = max(1, y2 - y1)
    left_corner = _point_from_anchors(anchor_points, "left_corner", (x1, y1 + mouth_h * 0.55))
    right_corner = _point_from_anchors(anchor_points, "right_corner", (x2 - 1, y1 + mouth_h * 0.55))
    left_inner = _point_from_anchors(anchor_points, "left_inner", left_corner)
    right_inner = _point_from_anchors(anchor_points, "right_inner", right_corner)
    upper_lip = _point_from_anchors(anchor_points, "upper_lip", ((x1 + x2) * 0.5, y1 + mouth_h * 0.38))
    lower_lip = _point_from_anchors(anchor_points, "lower_lip", ((x1 + x2) * 0.5, y1 + mouth_h * 0.66))

    left_x = float(left_inner[0])
    right_x = float(right_inner[0])
    center_x = (left_x + right_x) * 0.5
    upper_y = float(upper_lip[1])
    lower_y = float(lower_lip[1])
    center_y = (upper_y + lower_y) * 0.5
    inner_w = max(1.0, abs(right_x - left_x))
    inner_h = max(1.0, abs(lower_y - upper_y))

    guard = np.zeros(target_mask.shape[:2], dtype=np.uint8)
    axes = (
        max(7, int(round(inner_w * 0.58 * float(scale)))),
        max(5, int(round(max(inner_h * 0.82, mouth_h * 0.13) * float(scale)))),
    )
    cv2.ellipse(
        guard,
        (int(round(center_x)), int(round(center_y))),
        axes,
        0,
        0,
        360,
        255,
        -1,
        cv2.LINE_AA,
    )

    rect_pad_x = int(round(inner_w * 0.08 * float(scale)))
    rect_pad_y = int(round(max(inner_h * 0.05, mouth_h * 0.02) * float(scale)))
    rect_x1 = max(0, int(round(min(left_x, right_x) - rect_pad_x)))
    rect_x2 = min(target_mask.shape[1], int(round(max(left_x, right_x) + rect_pad_x)))
    rect_y1 = max(0, int(round(min(upper_y, lower_y) - rect_pad_y)))
    rect_y2 = min(target_mask.shape[0], int(round(max(upper_y, lower_y) + rect_pad_y)))
    if rect_x2 > rect_x1 and rect_y2 > rect_y1:
        guard[rect_y1:rect_y2, rect_x1:rect_x2] = 255

    if keepout_mask is not None and np.any(keepout_mask):
        keepout = (keepout_mask > 0).astype(np.uint8) * 255
        kernel = cv2.getStructuringElement(cv2.MORPH_ELLIPSE, (7, 5))
        keepout = cv2.dilate(keepout, kernel, iterations=1)
        guard = cv2.max(guard, keepout)

    blur_size = _odd_at_least(max(5, int(round(mouth_w * 0.030))))
    guard = cv2.GaussianBlur(guard, (blur_size, blur_size), 0)
    return np.clip(guard.astype(np.float32) / 255.0, 0.0, 1.0)


def _preserve_mouth_inner(base_bgr, edited_bgr, change_mask, target_mask, anchor_points, cv2, np, keepout_mask=None):
    inner_alpha = _build_mouth_inner_guard_alpha(target_mask, anchor_points, cv2, np, keepout_mask=keepout_mask, scale=0.78)
    if not np.any(inner_alpha):
        return edited_bgr, change_mask

    restore_alpha = np.clip(inner_alpha * 0.97, 0.0, 0.97)[..., None]
    restored = (
        base_bgr.astype(np.float32) * restore_alpha
        + edited_bgr.astype(np.float32) * (1.0 - restore_alpha)
    ).clip(0, 255).astype(np.uint8)
    hard_inner = inner_alpha > 0.75
    if np.any(hard_inner):
        restored[hard_inner] = base_bgr[hard_inner]
    protected_mask = _attenuate_mask_by_alpha(change_mask, inner_alpha, np, strength=1.05)
    protected_mask[inner_alpha > 0.58] = 0
    return restored, protected_mask


def _build_upper_lip_skin_guard_alpha(target_mask, anchor_points, cv2, np, scale: float = 1.0):
    bbox = compute_mask_bbox(target_mask, np)
    if bbox is None:
        return np.zeros(target_mask.shape[:2], dtype=np.float32)

    x1, y1, x2, y2 = bbox
    mouth_w = max(1, x2 - x1)
    mouth_h = max(1, y2 - y1)
    left_corner = _point_from_anchors(anchor_points, "left_corner", (x1, y1 + mouth_h * 0.55))
    right_corner = _point_from_anchors(anchor_points, "right_corner", (x2 - 1, y1 + mouth_h * 0.55))
    upper_lip = _point_from_anchors(anchor_points, "upper_lip", ((x1 + x2) * 0.5, y1 + mouth_h * 0.38))
    upper_outer = _point_from_anchors(anchor_points, "upper_outer", ((x1 + x2) * 0.5, y1 + mouth_h * 0.20))

    left_x = float(left_corner[0])
    right_x = float(right_corner[0])
    center_x = (left_x + right_x) * 0.5
    upper_inner_y = float(upper_lip[1])
    upper_outer_y = float(upper_outer[1])
    anchor_w = max(1.0, abs(right_x - left_x), mouth_w * 0.72)
    upper_depth = max(2.0, abs(upper_inner_y - upper_outer_y), mouth_h * 0.13)
    guard_h = max(3.0, upper_depth * 0.78, mouth_h * 0.10) * float(scale)
    guard_overlap = max(1.0, min(upper_depth * 0.18, mouth_h * 0.035)) * float(scale)

    guard = np.zeros(target_mask.shape[:2], dtype=np.uint8)
    rect_x1 = max(0, int(round(min(left_x, right_x) - anchor_w * 0.02)))
    rect_x2 = min(target_mask.shape[1], int(round(max(left_x, right_x) + anchor_w * 0.02)))
    rect_y1 = max(0, int(round(upper_outer_y - guard_h)))
    rect_y2 = min(target_mask.shape[0], int(round(upper_outer_y + guard_overlap)))
    if rect_x2 > rect_x1 and rect_y2 > rect_y1:
        guard[rect_y1:rect_y2, rect_x1:rect_x2] = 255

    cv2.ellipse(
        guard,
        (int(round(center_x)), int(round(upper_outer_y - guard_h * 0.22))),
        (
            max(7, int(round(anchor_w * 0.54 * float(scale)))),
            max(3, int(round(guard_h * 0.72))),
        ),
        0,
        0,
        360,
        255,
        -1,
        cv2.LINE_AA,
    )
    blur_size = _odd_at_least(max(3, int(round(mouth_w * 0.025))))
    guard = cv2.GaussianBlur(guard, (blur_size, blur_size), 0)
    return np.clip(guard.astype(np.float32) / 255.0, 0.0, 1.0)


def _preserve_upper_lip_skin(base_bgr, edited_bgr, change_mask, target_mask, anchor_points, cv2, np):
    skin_alpha = _build_upper_lip_skin_guard_alpha(target_mask, anchor_points, cv2, np, scale=1.08)
    if not np.any(skin_alpha):
        return edited_bgr, change_mask

    if anchor_points and "upper_outer" in anchor_points:
        _h = skin_alpha.shape[0]
        _skin_cutoff_y = max(0, int(anchor_points["upper_outer"][1]) - 14)
        skin_alpha = skin_alpha.copy()
        skin_alpha[_skin_cutoff_y:, :] = 0.0

    restore_alpha = np.clip(skin_alpha * 0.98, 0.0, 0.98)[..., None]
    restored = (
        base_bgr.astype(np.float32) * restore_alpha
        + edited_bgr.astype(np.float32) * (1.0 - restore_alpha)
    ).clip(0, 255).astype(np.uint8)
    hard_skin = skin_alpha > 0.78
    if np.any(hard_skin):
        restored[hard_skin] = base_bgr[hard_skin]
    protected_mask = _attenuate_mask_by_alpha(change_mask, skin_alpha, np, strength=1.10)
    protected_mask[skin_alpha > 0.68] = 0
    return restored, protected_mask


def _build_upper_lip_guard_alpha(target_mask, anchor_points, cv2, np, scale: float = 1.0):
    bbox = compute_mask_bbox(target_mask, np)
    if bbox is None:
        return np.zeros(target_mask.shape[:2], dtype=np.float32)

    x1, y1, x2, y2 = bbox
    mouth_w = max(1, x2 - x1)
    mouth_h = max(1, y2 - y1)
    left_corner = _point_from_anchors(anchor_points, "left_corner", (x1, y1 + mouth_h * 0.55))
    right_corner = _point_from_anchors(anchor_points, "right_corner", (x2 - 1, y1 + mouth_h * 0.55))
    upper_lip = _point_from_anchors(anchor_points, "upper_lip", ((x1 + x2) * 0.5, y1 + mouth_h * 0.38))
    upper_outer = _point_from_anchors(anchor_points, "upper_outer", ((x1 + x2) * 0.5, y1 + mouth_h * 0.26))

    left_x = float(left_corner[0])
    right_x = float(right_corner[0])
    center_x = (left_x + right_x) * 0.5
    upper_inner_y = float(upper_lip[1])
    upper_outer_y = min(float(upper_outer[1]), upper_inner_y)
    anchor_w = max(1.0, abs(right_x - left_x), mouth_w * 0.72)
    upper_depth = max(2.0, abs(upper_inner_y - upper_outer_y), mouth_h * 0.08)

    guard = np.zeros(target_mask.shape[:2], dtype=np.uint8)
    rect_x1 = max(0, int(round(min(left_x, right_x) - anchor_w * 0.08 * float(scale))))
    rect_x2 = min(target_mask.shape[1], int(round(max(left_x, right_x) + anchor_w * 0.08 * float(scale))))
    rect_y1 = max(0, int(round(upper_outer_y - upper_depth * 0.72 * float(scale))))
    rect_y2 = min(target_mask.shape[0], int(round(upper_inner_y + upper_depth * 0.30 * float(scale))))
    if rect_x2 > rect_x1 and rect_y2 > rect_y1:
        guard[rect_y1:rect_y2, rect_x1:rect_x2] = 255

    cv2.ellipse(
        guard,
        (int(round(center_x)), int(round((upper_outer_y * 0.48) + (upper_inner_y * 0.52)))),
        (
            max(8, int(round(anchor_w * 0.58 * float(scale)))),
            max(4, int(round(upper_depth * 1.42 * float(scale)))),
        ),
        0,
        0,
        360,
        255,
        -1,
        cv2.LINE_AA,
    )
    blur_size = _odd_at_least(max(3, int(round(mouth_w * 0.024))))
    guard = cv2.GaussianBlur(guard, (blur_size, blur_size), 0)
    return np.clip(guard.astype(np.float32) / 255.0, 0.0, 1.0)


def _preserve_upper_lip(base_bgr, edited_bgr, change_mask, target_mask, anchor_points, cv2, np):
    upper_alpha = _build_upper_lip_guard_alpha(target_mask, anchor_points, cv2, np, scale=1.10)
    if not np.any(upper_alpha):
        return edited_bgr, change_mask

    restore_alpha = np.clip(upper_alpha * 0.995, 0.0, 0.995)[..., None]
    restored = (
        base_bgr.astype(np.float32) * restore_alpha
        + edited_bgr.astype(np.float32) * (1.0 - restore_alpha)
    ).clip(0, 255).astype(np.uint8)
    hard_upper = upper_alpha > 0.34
    if np.any(hard_upper):
        restored[hard_upper] = base_bgr[hard_upper]

    protected_mask = _attenuate_mask_by_alpha(change_mask, upper_alpha, np, strength=1.25)
    protected_mask[upper_alpha > 0.18] = 0
    return restored, protected_mask


def _build_lower_lip_texture_alpha(target_mask, anchor_points, cv2, np, scale_y: float = 1.0):
    bbox = compute_mask_bbox(target_mask, np)
    if bbox is None:
        return np.zeros(target_mask.shape[:2], dtype=np.float32)

    x1, y1, x2, y2 = bbox
    mouth_w = max(1, x2 - x1)
    mouth_h = max(1, y2 - y1)
    left_corner = _point_from_anchors(anchor_points, "left_corner", (x1, y1 + mouth_h * 0.55))
    right_corner = _point_from_anchors(anchor_points, "right_corner", (x2 - 1, y1 + mouth_h * 0.55))
    lower_lip = _point_from_anchors(anchor_points, "lower_lip", ((x1 + x2) * 0.5, y1 + mouth_h * 0.66))
    lower_outer = _point_from_anchors(anchor_points, "lower_outer", ((x1 + x2) * 0.5, y1 + mouth_h * 0.78))

    left_x = float(left_corner[0])
    right_x = float(right_corner[0])
    center_x = (left_x + right_x) * 0.5
    lower_inner_y = float(lower_lip[1])
    lower_outer_y = max(float(lower_outer[1]), lower_inner_y)
    anchor_w = max(1.0, abs(right_x - left_x), mouth_w * 0.72)
    lower_depth = max(2.0, abs(lower_outer_y - lower_inner_y), mouth_h * 0.08)

    band = np.zeros(target_mask.shape[:2], dtype=np.uint8)
    cv2.ellipse(
        band,
        (int(round(center_x)), int(round((lower_inner_y * 0.42) + (lower_outer_y * 0.58)))),
        (
            max(8, int(round(anchor_w * 0.57))),
            max(4, int(round(lower_depth * (1.18 + max(0.0, float(scale_y) - 1.0) * 0.20)))),
        ),
        0,
        0,
        360,
        255,
        -1,
        cv2.LINE_AA,
    )
    band = cv2.bitwise_and(band, (target_mask > 0).astype(np.uint8) * 255)
    blur_size = _odd_at_least(max(5, int(round(mouth_w * 0.035))))
    band = cv2.GaussianBlur(band, (blur_size, blur_size), 0)
    return np.clip(band.astype(np.float32) / 255.0, 0.0, 1.0)


def _soften_lower_lip_texture(edited_bgr, change_mask, target_mask, anchor_points, cv2, np, scale_y: float = 1.0):
    lower_alpha = _build_lower_lip_texture_alpha(target_mask, anchor_points, cv2, np, scale_y=scale_y)
    if not np.any(lower_alpha) or not np.any(change_mask):
        return edited_bgr

    change_alpha = np.clip(change_mask.astype(np.float32) / 255.0, 0.0, 1.0)
    alpha = np.clip(lower_alpha * change_alpha * 0.28, 0.0, 0.28)[..., None]
    if not np.any(alpha):
        return edited_bgr

    smoothed = cv2.bilateralFilter(edited_bgr, 5, 18, 7)
    return (
        edited_bgr.astype(np.float32) * (1.0 - alpha)
        + smoothed.astype(np.float32) * alpha
    ).clip(0, 255).astype(np.uint8)

def _build_lower_mouth_skin_guard_alpha(target_mask, anchor_points, cv2, np, scale: float = 1.0):
    bbox = compute_mask_bbox(target_mask, np)
    if bbox is None:
        return np.zeros(target_mask.shape[:2], dtype=np.float32)

    x1, y1, x2, y2 = bbox
    mouth_w = max(1, x2 - x1)
    mouth_h = max(1, y2 - y1)
    left_corner = _point_from_anchors(anchor_points, "left_corner", (x1, y1 + mouth_h * 0.55))
    right_corner = _point_from_anchors(anchor_points, "right_corner", (x2 - 1, y1 + mouth_h * 0.55))
    lower_lip = _point_from_anchors(anchor_points, "lower_lip", ((x1 + x2) * 0.5, y1 + mouth_h * 0.66))
    lower_outer = _point_from_anchors(anchor_points, "lower_outer", ((x1 + x2) * 0.5, y1 + mouth_h * 0.78))

    left_x = float(left_corner[0])
    right_x = float(right_corner[0])
    lower_inner_y = float(lower_lip[1])
    lower_outer_y = max(float(lower_outer[1]), lower_inner_y)
    anchor_w = max(1.0, abs(right_x - left_x), mouth_w * 0.72)
    lower_depth = max(2.0, abs(lower_outer_y - lower_inner_y), mouth_h * 0.09)

    start_y = lower_outer_y + max(0.0, lower_depth * 0.02)
    transition = max(3.0, lower_depth * 0.82, mouth_h * 0.07) * float(scale)
    guard_x1 = max(0.0, min(left_x, right_x) - anchor_w * 0.18)
    guard_x2 = min(float(target_mask.shape[1] - 1), max(left_x, right_x) + anchor_w * 0.18)
    x_soft = max(3.0, anchor_w * 0.055)

    grid_y, grid_x = np.indices(target_mask.shape[:2], dtype=np.float32)
    vertical_alpha = _smoothstep((grid_y - float(start_y)) / float(max(1.0, transition)), np)
    left_alpha = _smoothstep((grid_x - float(guard_x1)) / float(x_soft), np)
    right_alpha = _smoothstep((float(guard_x2) - grid_x) / float(x_soft), np)
    horizontal_alpha = np.minimum(left_alpha, right_alpha)
    alpha = np.clip(vertical_alpha * horizontal_alpha, 0.0, 1.0)
    return alpha.astype(np.float32)


def _preserve_lower_mouth_skin(base_bgr, edited_bgr, change_mask, target_mask, anchor_points, cv2, np, scale_y: float = 1.0):
    lower_alpha = _build_lower_mouth_skin_guard_alpha(
        target_mask,
        anchor_points,
        cv2,
        np,
        scale=1.0 + max(0.0, float(scale_y) - 1.0) * 0.16,
    )
    if not np.any(lower_alpha):
        return edited_bgr, change_mask

    restore_strength = 0.97 if float(scale_y) > 1.0 else 0.90
    restore_alpha = np.clip(lower_alpha * restore_strength, 0.0, 0.98)[..., None]
    restored = (
        base_bgr.astype(np.float32) * restore_alpha
        + edited_bgr.astype(np.float32) * (1.0 - restore_alpha)
    ).clip(0, 255).astype(np.uint8)
    hard_lower = lower_alpha > 0.48
    if np.any(hard_lower):
        restored[hard_lower] = base_bgr[hard_lower]

    protected_mask = _attenuate_mask_by_alpha(change_mask, lower_alpha, np, strength=1.25)
    protected_mask[lower_alpha > 0.20] = 0
    return restored, protected_mask


def _adapt_mouth_geometry_to_pose(target_mask, anchor_points, np, scale_x: float, scale_y: float):
    eff_scale_x = float(scale_x)
    eff_scale_y = float(scale_y)
    bbox = compute_mask_bbox(target_mask, np)
    if bbox is None or not anchor_points:
        return eff_scale_x, eff_scale_y

    x1, y1, x2, y2 = bbox
    mouth_h = max(1, y2 - y1)
    left_corner = _point_from_anchors(anchor_points, "left_corner", (x1, y1 + mouth_h * 0.55))
    right_corner = _point_from_anchors(anchor_points, "right_corner", (x2 - 1, y1 + mouth_h * 0.55))
    upper_lip = _point_from_anchors(anchor_points, "upper_lip", ((x1 + x2) * 0.5, y1 + mouth_h * 0.38))
    lower_lip = _point_from_anchors(anchor_points, "lower_lip", ((x1 + x2) * 0.5, y1 + mouth_h * 0.66))

    left_x, left_y = float(left_corner[0]), float(left_corner[1])
    right_x, right_y = float(right_corner[0]), float(right_corner[1])
    anchor_w = max(1.0, abs(right_x - left_x))
    inner_h = max(1.0, abs(float(lower_lip[1]) - float(upper_lip[1])))
    open_ratio = inner_h / anchor_w
    open_factor = float(np.clip((open_ratio - 0.11) / 0.12, 0.0, 1.0))

    lip_center_y = (float(upper_lip[1]) + float(lower_lip[1])) * 0.5
    corner_y_mean = (left_y + right_y) * 0.5
    smile_factor = float(np.clip(((lip_center_y - corner_y_mean) / inner_h) / 0.8, 0.0, 1.0))

    if eff_scale_y > 1.0:
        y_damping = float(np.clip(1.0 - open_factor * 0.34 - smile_factor * 0.18, 0.52, 1.0))
        eff_scale_y = 1.0 + (eff_scale_y - 1.0) * y_damping
        eff_scale_y = max(1.12, eff_scale_y)
    if eff_scale_x > 1.0:
        x_damping = float(np.clip(1.0 - smile_factor * 0.22 - open_factor * 0.08, 0.68, 1.0))
        eff_scale_x = 1.0 + (eff_scale_x - 1.0) * x_damping
    return eff_scale_x, eff_scale_y

def _build_mouth_center_protection(target_mask, anchor_points, cv2, np):
    bbox = compute_mask_bbox(target_mask, np)
    if bbox is None:
        return np.zeros(target_mask.shape[:2], dtype=np.uint8)

    x1, y1, x2, y2 = bbox
    mouth_w = max(1, x2 - x1)
    mouth_h = max(1, y2 - y1)
    left_corner = _point_from_anchors(anchor_points, "left_corner", (x1, y1 + mouth_h * 0.55))
    right_corner = _point_from_anchors(anchor_points, "right_corner", (x2 - 1, y1 + mouth_h * 0.55))
    upper_lip = _point_from_anchors(anchor_points, "upper_lip", ((x1 + x2) * 0.5, y1 + mouth_h * 0.38))
    lower_lip = _point_from_anchors(anchor_points, "lower_lip", ((x1 + x2) * 0.5, y1 + mouth_h * 0.66))

    left_x, left_y = float(left_corner[0]), float(left_corner[1])
    right_x, right_y = float(right_corner[0]), float(right_corner[1])
    center_x = (left_x + right_x) * 0.5
    center_y = (float(upper_lip[1]) + float(lower_lip[1])) * 0.5
    anchor_w = max(1.0, abs(right_x - left_x))
    anchor_h = max(1.0, abs(float(lower_lip[1]) - float(upper_lip[1])), mouth_h * 0.28)

    protected = np.zeros(target_mask.shape[:2], dtype=np.uint8)
    axes = (
        max(6, int(round(anchor_w * 0.40))),
        max(5, int(round(anchor_h * 1.05))),
    )
    cv2.ellipse(
        protected,
        (int(round(center_x)), int(round(center_y))),
        axes,
        0,
        0,
        360,
        255,
        -1,
        cv2.LINE_AA,
    )

    x_margin = int(round(anchor_w * 0.20))
    y_margin = int(round(max(anchor_h * 0.80, mouth_h * 0.18)))
    rect_x1 = max(0, int(round(min(left_x, right_x) + x_margin)))
    rect_x2 = min(target_mask.shape[1], int(round(max(left_x, right_x) - x_margin)))
    rect_y1 = max(0, int(round(center_y - y_margin)))
    rect_y2 = min(target_mask.shape[0], int(round(center_y + y_margin)))
    if rect_x2 > rect_x1 and rect_y2 > rect_y1:
        protected[rect_y1:rect_y2, rect_x1:rect_x2] = 255

    protected = cv2.bitwise_and(protected, (target_mask > 0).astype(np.uint8) * 255)
    return protected


def _piecewise_affine_warp(base_bgr, source_points, dest_points, support_mask, cv2, np):
    try:
        from scipy.spatial import Delaunay
    except Exception:
        return base_bgr, np.zeros(support_mask.shape[:2], dtype=np.uint8)

    source_points = np.asarray(source_points, dtype=np.float32)
    dest_points = np.asarray(dest_points, dtype=np.float32)
    if source_points.shape != dest_points.shape or source_points.shape[0] < 3:
        return base_bgr, np.zeros(support_mask.shape[:2], dtype=np.uint8)

    height, width = base_bgr.shape[:2]
    dest_points[:, 0] = np.clip(dest_points[:, 0], 0, width - 1)
    dest_points[:, 1] = np.clip(dest_points[:, 1], 0, height - 1)
    source_points[:, 0] = np.clip(source_points[:, 0], 0, width - 1)
    source_points[:, 1] = np.clip(source_points[:, 1], 0, height - 1)

    try:
        triangulation = Delaunay(dest_points)
    except Exception:
        return base_bgr, np.zeros(support_mask.shape[:2], dtype=np.uint8)

    warped = base_bgr.copy()
    changed = np.zeros(support_mask.shape[:2], dtype=np.uint8)
    for triangle_indices in triangulation.simplices:
        src_tri = source_points[triangle_indices].astype(np.float32)
        dst_tri = dest_points[triangle_indices].astype(np.float32)
        if abs(cv2.contourArea(dst_tri)) < 1.0 or abs(cv2.contourArea(src_tri)) < 1.0:
            continue

        sx, sy, sw, sh = cv2.boundingRect(src_tri)
        dx, dy, dw, dh = cv2.boundingRect(dst_tri)
        if sw <= 1 or sh <= 1 or dw <= 1 or dh <= 1:
            continue
        sx, sy = max(0, sx), max(0, sy)
        dx, dy = max(0, dx), max(0, dy)
        sw = min(sw, width - sx)
        sh = min(sh, height - sy)
        dw = min(dw, width - dx)
        dh = min(dh, height - dy)
        if sw <= 1 or sh <= 1 or dw <= 1 or dh <= 1:
            continue

        src_local = src_tri - np.array([sx, sy], dtype=np.float32)
        dst_local = dst_tri - np.array([dx, dy], dtype=np.float32)
        matrix = cv2.getAffineTransform(src_local, dst_local)
        source_patch = base_bgr[sy : sy + sh, sx : sx + sw]
        warped_patch = cv2.warpAffine(
            source_patch,
            matrix,
            (dw, dh),
            flags=cv2.INTER_LINEAR,
            borderMode=cv2.BORDER_REFLECT_101,
        )

        triangle_mask = np.zeros((dh, dw), dtype=np.uint8)
        cv2.fillConvexPoly(triangle_mask, np.round(dst_local).astype(np.int32), 255, cv2.LINE_AA)
        support_patch = support_mask[dy : dy + dh, dx : dx + dw]
        triangle_mask = cv2.bitwise_and(triangle_mask, support_patch)
        if not np.any(triangle_mask):
            continue

        alpha = cv2.GaussianBlur(triangle_mask, (3, 3), 0).astype(np.float32) / 255.0
        alpha = alpha[..., None]
        target_patch = warped[dy : dy + dh, dx : dx + dw].astype(np.float32)
        warped[dy : dy + dh, dx : dx + dw] = (
            target_patch * (1.0 - alpha) + warped_patch.astype(np.float32) * alpha
        ).clip(0, 255).astype(np.uint8)
        changed[dy : dy + dh, dx : dx + dw] = cv2.max(changed[dy : dy + dh, dx : dx + dw], triangle_mask)

    warped[support_mask <= 0] = base_bgr[support_mask <= 0]
    return warped, changed


def _warp_mouth_smile(base_bgr, target_mask, anchor_points, cv2, np, strength: float, feather: int, keepout_mask=None):
    hard_target = (target_mask > 0).astype(np.uint8) * 255

    bbox = compute_mask_bbox(hard_target, np)
    if bbox is None or strength <= 0:
        return base_bgr, target_mask

    image_h, image_w = target_mask.shape[:2]
    x1, y1, x2, y2 = bbox
    mouth_w = max(1, x2 - x1)
    mouth_h = max(1, y2 - y1)
    left_corner = _point_from_anchors(anchor_points, "left_corner", (x1, y1 + mouth_h * 0.55))
    right_corner = _point_from_anchors(anchor_points, "right_corner", (x2 - 1, y1 + mouth_h * 0.55))
    upper_lip = _point_from_anchors(anchor_points, "upper_lip", ((x1 + x2) * 0.5, y1 + mouth_h * 0.38))
    lower_lip = _point_from_anchors(anchor_points, "lower_lip", ((x1 + x2) * 0.5, y1 + mouth_h * 0.66))
    upper_outer = _point_from_anchors(anchor_points, "upper_outer", ((x1 + x2) * 0.5, y1 + mouth_h * 0.26))
    lower_outer = _point_from_anchors(anchor_points, "lower_outer", ((x1 + x2) * 0.5, y1 + mouth_h * 0.78))

    left_x, left_y = float(left_corner[0]), float(left_corner[1])
    right_x, right_y = float(right_corner[0]), float(right_corner[1])
    center_x = (left_x + right_x) * 0.5
    center_y = (left_y + right_y + float(upper_lip[1]) + float(lower_lip[1])) * 0.25
    anchor_w = max(1.0, abs(right_x - left_x), mouth_w * 0.56)
    anchor_h = max(1.0, abs(float(lower_lip[1]) - float(upper_lip[1])), mouth_h * 0.14, anchor_w * 0.035)

