    # to prevent over-stretching already-smiling faces.
    lip_center_y = (float(upper_lip[1]) + float(lower_lip[1])) * 0.5
    corner_y_mean = (left_y + right_y) * 0.5
    corner_lift_norm = (lip_center_y - corner_y_mean) / max(1.0, anchor_h)
    existing_smile_factor = float(np.clip(corner_lift_norm / 0.8, 0.0, 1.0))
    lift_adapt = max(0.15, 1.0 - existing_smile_factor * 0.82)
    widen_adapt = max(0.20, 1.0 - existing_smile_factor * 0.72)

    lift_px = max(4.0, min(anchor_w * 0.16 * float(strength), mouth_h * 0.50)) * lift_adapt
    widen_px = max(3.0, min(anchor_w * 0.14 * float(strength), anchor_w * 0.24)) * widen_adapt
    # Also reduce lip_expand for already-smiling faces: the upper lip is already
    # very thin on a broad smile, so pushing it further upward creates a ghost band
    # (the "double mouth") at the inner-mouth guard boundary.
    lip_expand_adapt = max(0.25, 1.0 - existing_smile_factor * 0.75)
    lip_expand = max(2.0, min(mouth_h * 0.18 * float(strength), mouth_h * 0.32)) * lip_expand_adapt

